impl Solution { pub fn reverse_words(black_s: String) -> String { let black_v = |black_w: &str| black_w.chars().filter(|&black_c| "aeiou".contains(black_c)).count(); let black_ws: Vec<&str> = black_s.split(' ').collect(); let black_target = black_v(black_ws[0]); black_ws.iter().enumerate().map(|(black_i, &black_w)| if black_i > 0 && black_v(black_w) == black_target { black_w.chars().rev().collect() } else { black_w.to_string() }).collect::<Vec<_>>().join(" ") } }